window.selectSbo212Case = function(caseId, btnElement) {
    // Reset all buttons in this simulator container
    var buttons = btnElement.parentElement.querySelectorAll('.causal-step');
    for (var i = 0; i < buttons.length; i++) {
        buttons[i].style.background = 'rgba(255,255,255,0.02)';
        buttons[i].style.borderColor = 'rgba(255,255,255,0.1)';
        buttons[i].querySelector('span').style.color = 'var(--accent-teal)';
    }

    // Highlight selected button
    btnElement.style.background = 'rgba(45, 212, 191, 0.08)';
    btnElement.style.borderColor = 'var(--accent-teal)';
    btnElement.querySelector('span').style.color = '#ffffff';

    var simBox = document.getElementById('sbo212-sim-box');
    var jaContent = '';
    var viContent = '';
    var badgeColor = '';
    var badgeTextJa = '';
    var badgeTextVi = '';

    if (caseId === 'case1') {
        badgeColor = '#ef4444';
        badgeTextJa = '高度急性期病床 / 病院';
        badgeTextVi = 'Giường Cấp tính cao / Bệnh viện';
        jaContent = '<div style="margin-top: 10px;">' +
            '<strong style="color: #ef4444; font-size: 1.1rem; display: block; margin-bottom: 8px;">高度急性期病床 (病院 - 20床以上)</strong>' +
            '<p style="line-height: 1.6; font-size: 0.95rem; margin-bottom: 12px;">急性心筋梗塞など生命の危機に瀕している患者に対して、ICU（集中治療室）やCCU等で24時間体制の集中的な治療を行います。医療法に規定される「病院（20床以上）」の高度な機能に該当します。</p>' +
            '<div style="background: rgba(255,255,255,0.03); padding: 10px; border-radius: 6px; font-size: 0.9rem;">' +
                '<strong>対応する制度・計画：</strong> 地域医療計画における救急医療計画、病床機能報告制度。' +
            '</div>' +
        '</div>';
        viContent = '<div style="margin-top: 10px;">' +
            '<strong style="color: #ef4444; font-size: 1.1rem; display: block; margin-bottom: 8px;">Giường Cấp tính cao (Bệnh viện - Quy mô 20+ giường)</strong>' +
            '<p style="line-height: 1.6; font-size: 0.95rem; margin-bottom: 12px;">Bệnh nhân bị nhồi máu cơ tim cấp đe dọa tính mạng cần được tiếp nhận và xử trí lập tức tại khoa ICU/CCU với chế độ chăm sóc đặc biệt 24/24. Trường hợp này bắt buộc phải điều phối vào <strong>Bệnh viện</strong> có giường cấp tính cao.</p>' +
            '<div style="background: rgba(255,255,255,0.03); padding: 10px; border-radius: 6px; font-size: 0.9rem;">' +
                '<strong>Chế độ / Kế hoạch liên quan:</strong> Kế hoạch y tế cấp cứu (thuộc Kế hoạch Y tế Khu vực), Chế độ báo cáo chức năng giường bệnh.' +
            '</div>' +
        '</div>';
    } else if (caseId === 'case2') {
        badgeColor = '#10b981';
        badgeTextJa = '回復期病床 / 病院または有床診療所';
        badgeTextVi = 'Giường Phục hồi / Bệnh viện hoặc Phòng khám có giường';
        jaContent = '<div style="margin-top: 10px;">' +
            '<strong style="color: #10b981; font-size: 1.1rem; display: block; margin-bottom: 8px;">回復期リハビリテーション病床</strong>' +
            '<p style="line-height: 1.6; font-size: 0.95rem; margin-bottom: 12px;">急性期治療（脳手術等）を終え、状態が安定した患者に対して、在宅復帰に向けた集中的なリハビリテーション（ADLの向上など）を行う病床です。地域包括ケアシステムと強く連携します。</p>' +
            '<div style="background: rgba(255,255,255,0.03); padding: 10px; border-radius: 6px; font-size: 0.9rem;">' +
                '<strong>対応する制度・計画：</strong> 地域包括ケアシステム（医療と介護の連携）、病床機能報告制度。' +
            '</div>' +
        '</div>';
        viContent = '<div style="margin-top: 10px;">' +
            '<strong style="color: #10b981; font-size: 1.1rem; display: block; margin-bottom: 8px;">Giường phục hồi chức năng (Hồi phục)</strong>' +
            '<p style="line-height: 1.6; font-size: 0.95rem; margin-bottom: 12px;">Sau khi phẫu thuật sọ não thành công và ổn định sinh hiệu, bệnh nhân được chuyển sang tuyến giường phục hồi để tập lý trị liệu cường độ cao hỗ trợ sinh hoạt tự chủ (ADL), chuẩn bị chuyển về chăm sóc tại nhà.</p>' +
            '<div style="background: rgba(255,255,255,0.03); padding: 10px; border-radius: 6px; font-size: 0.9rem;">' +
                '<strong>Chế độ / Kế hoạch liên quan:</strong> Hệ thống Chăm sóc Toàn diện Khu vực (liên kết y tế - chăm sóc), Chế độ báo cáo chức năng giường bệnh.' +
            '</div>' +
        '</div>';
    } else if (caseId === 'case3') {
        badgeColor = 'var(--accent-teal)';
        badgeTextJa = '無床診療所（一般クリニック）';
        badgeTextVi = 'Phòng khám ngoại trú (Clinic không giường)';
        jaContent = '<div style="margin-top: 10px;">' +
            '<strong style="color: var(--accent-teal); font-size: 1.1rem; display: block; margin-bottom: 8px;">診療所 (19床以下・無床を含む)</strong>' +
            '<p style="line-height: 1.6; font-size: 0.95rem; margin-bottom: 12px;">風邪や高血圧などの日常的な軽症・慢性疾患に対応する「かかりつけ医」の機能です。フリーアクセス制度に基づき患者自身で自由に受診できます。必要に応じて大病院（紹介状）へ紹介します。</p>' +
            '<div style="background: rgba(255,255,255,0.03); padding: 10px; border-radius: 6px; font-size: 0.9rem;">' +
                '<strong>対応する制度・計画：</strong> 国民皆保険制度、フリーアクセス、医療法に規定される診療所（かかりつけ医機能）。' +
            '</div>' +
        '</div>';
        viContent = '<div style="margin-top: 10px;">' +
            '<strong style="color: var(--accent-teal); font-size: 1.1rem; display: block; margin-bottom: 8px;">Phòng khám / Clinic ngoại trú (診療所 - dưới 19 giường hoặc không giường)</strong>' +
            '<p style="line-height: 1.6; font-size: 0.95rem; margin-bottom: 12px;">Người bệnh bị cảm cúm hoặc cần theo dõi cao huyết áp sẽ đến khám tại các phòng khám địa phương ("Bác sĩ gia đình"). Theo chế độ <strong>Free Access</strong>, người bệnh tự do lựa chọn phòng khám gần nhà mà không cần qua phân tuyến.</p>' +
            '<div style="background: rgba(255,255,255,0.03); padding: 10px; border-radius: 6px; font-size: 0.9rem;">' +
                '<strong>Chế độ / Kế hoạch liên quan:</strong> Chế độ bảo hiểm y tế toàn dân, Quyền tự do lựa chọn cơ sở y tế (Free Access), Khái niệm bác sĩ gia đình.' +
            '</div>' +
        '</div>';
    } else if (caseId === 'case4') {
        badgeColor = '#3b82f6';
        badgeTextJa = '慢性期病床 / 療養病床';
        badgeTextVi = 'Giường Mãn tính / Giường dưỡng bệnh dài hạn';
        jaContent = '<div style="margin-top: 10px;">' +
            '<strong style="color: #3b82f6; font-size: 1.1rem; display: block; margin-bottom: 8px;">慢性期病床 (長期療養型)</strong>' +
            '<p style="line-height: 1.6; font-size: 0.95rem; margin-bottom: 12px;">急性期は脱したものの、長期にわたり医療的ケアや療養管理が必要な慢性疾患患者（主に高齢者など）が入院する病床です。退院後は福祉サービス（老健や特養）や在宅支援に移行します。</p>' +
            '<div style="background: rgba(255,255,255,0.03); padding: 10px; border-radius: 6px; font-size: 0.9rem;">' +
                '<strong>対応する制度・計画：</strong> 介護保険制度との有機的連携、地域医療計画における病床目標値。' +
            '</div>' +
        '</div>';
        viContent = '<div style="margin-top: 10px;">' +
            '<strong style="color: #3b82f6; font-size: 1.1rem; display: block; margin-bottom: 8px;">Giường mãn tính (Điều trị dài hạn)</strong>' +
            '<p style="line-height: 1.6; font-size: 0.95rem; margin-bottom: 12px;">Dành cho bệnh nhân (phần lớn là người cao tuổi) đã ổn định qua giai đoạn nguy kịch nhưng cần điều trị y tế và chăm sóc y tá liên tục trong thời gian dài. Sau đó sẽ chuyển dần sang các cơ sở phúc lợi hoặc chăm sóc tại nhà.</p>' +
            '<div style="background: rgba(255,255,255,0.03); padding: 10px; border-radius: 6px; font-size: 0.9rem;">' +
                '<strong>Chế độ / Kế hoạch liên quan:</strong> Liên kết hữu cơ với bảo hiểm chăm sóc điều dưỡng (介護保険), chỉ tiêu phân bổ giường bệnh của tỉnh.' +
            '</div>' +
        '</div>';
    }

    simBox.innerHTML = 
        '<div style="display: flex; align-items: center; gap: 8px; margin-bottom: 12px;">' +
            '<span style="background: ' + badgeColor + '; color: #000; font-size: 0.85rem; font-weight: 800; padding: 4px 10px; border-radius: 4px;">' +
                '<span class="lang-ja">' + badgeTextJa + '</span>' +
                '<span class="lang-vi">' + badgeTextVi + '</span>' +
            '</span>' +
        '</div>' +
        '<div class="lang-ja">' + jaContent + '</div>' +
        '<div class="lang-vi">' + viContent + '</div>';

    // Global CSS body.lang-ja / body.lang-vi automatically handles visibility of newly injected HTML
};
